}catch{$script:runComplete=(Get-Date).ToUniversalTime();Save 'failed' $_.Exception.Message;exit 2}finally{if($expert){Remove-Item $expert -Force -ErrorAction SilentlyContinue};if($result){Remove-Item $result -Force -ErrorAction SilentlyContinue}}